import{_ as e,Z as t,u as s,x as d}from"./chunks/framework.CA1zxVjD.js";const g=JSON.parse('{"title":"Cinem Script Language","description":"","frontmatter":{},"headers":[],"relativePath":"Documentacion/Tutoriales Varios/Cinem Script Language.md","filePath":"Documentacion/Tutoriales Varios/Cinem Script Language.md"}'),i={name:"Documentacion/Tutoriales Varios/Cinem Script Language.md"};function n(o,a,l,c,r,p){return t(),s("div",null,[...a[0]||(a[0]=[d(`<h1 id="cinem-script-language" tabindex="-1">Cinem Script Language <a class="header-anchor" href="#cinem-script-language" aria-label="Permalink to “Cinem Script Language”">​</a></h1><p>Lenguaje de scripting para definir secuencias cinemáticas. Los archivos usan la extensión <code>.cinem</code> y son leídos línea a línea, ejecutando cada comando en orden mediante una cola interna.</p><hr><h2 id="resumen-de-comandos" tabindex="-1">Resumen de comandos <a class="header-anchor" href="#resumen-de-comandos" aria-label="Permalink to “Resumen de comandos”">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Parámetros</th><th>Tags</th><th>Bloquea</th><th>Descripción</th></tr></thead><tbody><tr><td><code>bg</code></td><td><code>asset</code></td><td><code>scale=0.5</code></td><td>❌</td><td>Carga una imagen de fondo</td></tr><tr><td><code>text</code></td><td><code>&quot;mensaje&quot;</code></td><td>—</td><td>❌</td><td>Muestra un subtítulo en pantalla</td></tr><tr><td><code>wait</code></td><td><code>ms</code></td><td>—</td><td>✅</td><td>Pausa la cola N milisegundos</td></tr><tr><td><code>imageFade</code></td><td><code>ms</code></td><td><code>noblock</code></td><td>✅</td><td>Fade in/out de la imagen actual</td></tr><tr><td><code>fade</code></td><td><code>ms</code></td><td>—</td><td>❌</td><td>Fade out global de pantalla</td></tr><tr><td><code>waitFade</code></td><td><code>ms</code></td><td>—</td><td>✅</td><td>Fade out global + espera N ms</td></tr><tr><td><code>fullWaitFade</code></td><td><code>ms</code></td><td>—</td><td>✅</td><td>Fade out global + espera N*2 ms</td></tr><tr><td><code>audio</code></td><td><code>asset</code></td><td>—</td><td>❌</td><td>Reproduce un efecto de sonido</td></tr><tr><td><code>scene</code></td><td><code>id</code></td><td>—</td><td>❌</td><td>Cambia a la escena con ese ID</td></tr><tr><td><code>#</code></td><td>—</td><td>—</td><td>❌</td><td>Comentario</td></tr><tr><td><code>global</code></td><td><code>alpha</code><br><code>...</code></td><td>el valor</td><td></td><td>Cambia una variable de la cinematica<br>Ej: global alpha 0.3 <br>Pone el alpha de la imagen a 0.3</td></tr></tbody></table><hr><h2 id="estructura-general" tabindex="-1">Estructura general <a class="header-anchor" href="#estructura-general" aria-label="Permalink to “Estructura general”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># Esto es un comentario</span></span>
<span class="line"><span>comando parametro [tag]</span></span>
<span class="line"><span>comando &quot;texto entre comillas&quot;</span></span></code></pre></div><ul><li>Cada línea es un comando independiente</li><li>Los comentarios empiezan con <code>#</code></li><li>Las líneas vacías se ignoran</li><li>Los comandos se ejecutan de forma <strong>secuencial</strong> — cada uno espera al anterior salvo que se use la tag <code>noblock</code></li><li>Los strings deben ir <strong>entre comillas dobles</strong></li></ul><hr><h2 id="comandos" tabindex="-1">Comandos <a class="header-anchor" href="#comandos" aria-label="Permalink to “Comandos”">​</a></h2><h3 id="bg-imagen-de-fondo" tabindex="-1"><code>bg</code> - Imagen de fondo <a class="header-anchor" href="#bg-imagen-de-fondo" aria-label="Permalink to “bg - Imagen de fondo”">​</a></h3><p>Carga y muestra una imagen de fondo. El asset debe estar registrado en el <code>ResourceManager</code>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>bg &lt;asset&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Extra</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>asset</code></td><td>0.3 (la escala de la imagen)</td><td>string</td><td>Nombre del asset de imagen</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>bg cinemOut1</span></span>
<span class="line"><span># Esto hace que la imagen este a un 20% del tamaño</span></span>
<span class="line"><span>bg fondoDesierto 0.2</span></span></code></pre></div><hr><h3 id="text-subtitulo" tabindex="-1"><code>text</code> - Subtítulo <a class="header-anchor" href="#text-subtitulo" aria-label="Permalink to “text - Subtítulo”">​</a></h3><p>Muestra un texto en la parte inferior de la pantalla. Para limpiar el texto, usar comillas vacías.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>text &quot;&lt;mensaje&gt;&quot;</span></span>
<span class="line"><span>text &quot;&quot;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>mensaje</code></td><td>string</td><td>Texto a mostrar entre comillas</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>text &quot;El páramo desolado invade el mundo&quot;</span></span>
<span class="line"><span>text &quot;&quot;</span></span></code></pre></div><hr><h3 id="wait-espera" tabindex="-1"><code>wait</code> - Espera <a class="header-anchor" href="#wait-espera" aria-label="Permalink to “wait - Espera”">​</a></h3><p>Pausa la ejecución de la cola de comandos durante un tiempo. <strong>Bloquea</strong> la cola hasta que transcurra el tiempo indicado.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>wait &lt;ms&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>ms</code></td><td>int</td><td>Milisegundos a esperar</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>wait 3000    # espera 3 segundos</span></span>
<span class="line"><span>wait 500     # espera medio segundo</span></span></code></pre></div><hr><h3 id="imagefade-fade-de-imagen" tabindex="-1"><code>imageFade</code> - Fade de imagen <a class="header-anchor" href="#imagefade-fade-de-imagen" aria-label="Permalink to “imageFade - Fade de imagen”">​</a></h3><p>Hace un fade in o fade out de la imagen actual. Detecta automáticamente la dirección: si el alpha es <code>0</code> hace fade <strong>in</strong>, si es <code>1</code> hace fade <strong>out</strong>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>imageFade &lt;ms&gt; [noblock]</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>ms</code></td><td>int</td><td>Duración del fade en milisegundos</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Tag</th><th>Descripción</th></tr></thead><tbody><tr><td><code>noblock</code></td><td>La cola de comandos continúa sin esperar al fade</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>imageFade 1000           # fade bloqueante de 1 segundo</span></span>
<span class="line"><span>imageFade 1000 noblock   # fade en paralelo, la cola sigue</span></span></code></pre></div><hr><h3 id="fade-fade-de-pantalla" tabindex="-1"><code>fade</code> - Fade de pantalla <a class="header-anchor" href="#fade-fade-de-pantalla" aria-label="Permalink to “fade - Fade de pantalla”">​</a></h3><p>Lanza el fade out global de la pantalla (a negro). No bloquea la cola de comandos.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fade &lt;ms&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>ms</code></td><td>float</td><td>Duración del fade en milisegundos</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fade 1000</span></span>
<span class="line"><span>fade 2000</span></span></code></pre></div><hr><h3 id="waitfade-fade-con-espera-simple" tabindex="-1"><code>waitFade</code> - Fade con espera simple <a class="header-anchor" href="#waitfade-fade-con-espera-simple" aria-label="Permalink to “waitFade - Fade con espera simple”">​</a></h3><p>Lanza el fade out global y además bloquea la cola durante la duración del fade.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>waitFade &lt;ms&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>ms</code></td><td>float</td><td>Duración del fade y de la espera</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>waitFade 1000    # hace fade y espera 1 segundo</span></span></code></pre></div><hr><h3 id="fullwaitfade-fade-con-espera-doble" tabindex="-1"><code>fullWaitFade</code> - Fade con espera doble <a class="header-anchor" href="#fullwaitfade-fade-con-espera-doble" aria-label="Permalink to “fullWaitFade - Fade con espera doble”">​</a></h3><p>Lanza el fade out global y bloquea la cola durante el <strong>doble</strong> de la duración del fade. Útil para dar tiempo a que el fade termine y haya una pausa adicional.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fullWaitFade &lt;ms&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>ms</code></td><td>float</td><td>Duración del fade; la espera será <code>ms * 2</code></td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>fullWaitFade 1000    # fade de 1s, bloquea 2s en total</span></span></code></pre></div><hr><h3 id="audio-reproducir-sonido" tabindex="-1"><code>audio</code> - Reproducir sonido <a class="header-anchor" href="#audio-reproducir-sonido" aria-label="Permalink to “audio - Reproducir sonido”">​</a></h3><p>Reproduce un efecto de sonido. El asset debe estar registrado en el <code>ResourceManager</code>.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>audio &lt;asset&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>asset</code></td><td>string</td><td>Nombre del asset de audio</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>audio explosion</span></span>
<span class="line"><span>audio musicaIntro</span></span></code></pre></div><hr><h3 id="scene-cambiar-de-escena" tabindex="-1"><code>scene</code> - Cambiar de escena <a class="header-anchor" href="#scene-cambiar-de-escena" aria-label="Permalink to “scene - Cambiar de escena”">​</a></h3><p>Finaliza la cinemática y solicita un cambio de escena por su ID numérico.</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>scene &lt;id&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Parámetro</th><th>Tipo</th><th>Descripción</th></tr></thead><tbody><tr><td><code>id</code></td><td>int</td><td>ID de la escena destino</td></tr></tbody></table><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>scene 1</span></span>
<span class="line"><span>scene 3</span></span></code></pre></div><hr><h2 id="tags" tabindex="-1">Tags <a class="header-anchor" href="#tags" aria-label="Permalink to “Tags”">​</a></h2><p>Las tags son modificadores opcionales que se añaden al final de un comando.</p><table tabindex="0"><thead><tr><th>Tag</th><th>Compatible con</th><th>Descripción</th></tr></thead><tbody><tr><td><code>noblock</code></td><td><code>imageFade</code></td><td>El comando no bloquea la cola; los siguientes se ejecutan en paralelo</td></tr></tbody></table><hr><h2 id="comportamiento-de-bloqueo" tabindex="-1">Comportamiento de bloqueo <a class="header-anchor" href="#comportamiento-de-bloqueo" aria-label="Permalink to “Comportamiento de bloqueo”">​</a></h2><p>Por defecto, los comandos que tienen duración bloquean la cola hasta completarse:</p><table tabindex="0"><thead><tr><th>Comando</th><th>Bloquea</th><th>Admite <code>noblock</code></th></tr></thead><tbody><tr><td><code>wait</code></td><td>✅</td><td>❌</td></tr><tr><td><code>imageFade</code></td><td>✅</td><td>✅</td></tr><tr><td><code>waitFade</code></td><td>✅</td><td>❌</td></tr><tr><td><code>fullWaitFade</code></td><td>✅</td><td>❌</td></tr><tr><td><code>fade</code></td><td>❌</td><td>—</td></tr><tr><td><code>bg</code></td><td>❌</td><td>—</td></tr><tr><td><code>text</code></td><td>❌</td><td>—</td></tr><tr><td><code>audio</code></td><td>❌</td><td>—</td></tr><tr><td><code>scene</code></td><td>❌</td><td>—</td></tr></tbody></table><hr><h2 id="ejemplo-completo" tabindex="-1">Ejemplo completo <a class="header-anchor" href="#ejemplo-completo" aria-label="Permalink to “Ejemplo completo”">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># Primera imagen</span></span>
<span class="line"><span>bg cinemOut1</span></span>
<span class="line"><span>text &quot;Estoy en el desierto con mi amada, mirando al infinito&quot;</span></span>
<span class="line"><span>wait 5000</span></span>
<span class="line"><span>imageFade 1000</span></span>
<span class="line"><span>text &quot;&quot;</span></span>
<span class="line"><span>wait 1000</span></span>
<span class="line"><span> </span></span>
<span class="line"><span># Segunda imagen</span></span>
<span class="line"><span>bg cinemOut2</span></span>
<span class="line"><span>imageFade 1000 noblock</span></span>
<span class="line"><span>text &quot;El páramo desolado invade el mundo después de la explosión de las bombas&quot;</span></span>
<span class="line"><span>wait 6000</span></span>
<span class="line"><span>fade 1000</span></span>
<span class="line"><span>wait 1000</span></span>
<span class="line"><span> </span></span>
<span class="line"><span># Tercera imagen con transición final</span></span>
<span class="line"><span>bg cinemOut3</span></span>
<span class="line"><span>text &quot;Pero siempre queda una chispa de esperanza&quot;</span></span>
<span class="line"><span>wait 4000</span></span>
<span class="line"><span>fade 2000</span></span>
<span class="line"><span>wait 2000</span></span>
<span class="line"><span>scene 1</span></span></code></pre></div><hr><h2 id="assets" tabindex="-1">Assets <a class="header-anchor" href="#assets" aria-label="Permalink to “Assets”">​</a></h2><p>Los archivos de cinemática se ubican en:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>assets/cinematic/&lt;nombre&gt;.cinem</span></span></code></pre></div><p>Los assets de imagen y audio referenciados deben estar previamente cargados en el <code>ResourceManager</code> del juego antes de ejecutar la cinemática.</p>`,81)])])}const b=e(i,[["render",n]]);export{g as __pageData,b as default};
